server {
    server_name xiaohongxia.ai1717.cn;

    client_max_body_size 50M;

    # Serve uploads directly from host with priority
    location ^~ /uploads/ {
        alias /home/dahongshu_uploads/;
        autoindex off;
        expires 30d;
        add_header Cache-Control \\"public, no-transform\\";

        # Security: disable script execution in uploads
        location ~* \\.\(php|pl|py|jsp|sh|cgi\)$ {
            deny all;
        }
    }

    # Also serve /api/uploads/ from host
    location ^~ /api/uploads/ {
        alias /home/dahongshu_uploads/;
        autoindex off;
        expires 30d;
        add_header Cache-Control \\"public, no-transform\\";

        location ~* \\.\(php|pl|py|jsp|sh|cgi\)$ {
            deny all;
        }
    }

    # Caching for other static files in public folder \(served by Next.js\)
    location ~* \\.\(?:ico|css|js|gif|jpe?g|png|svg|webp\)$ {
        proxy_pass http://localhost:3100;
        proxy_set_header Host \\$host;
        expires 30d;
        add_header Cache-Control \\"public, no-transform\\";
    }

    location / {
        proxy_pass http://localhost:3100;
        proxy_set_header Host \\$host;
        proxy_set_header X-Real-IP \\$remote_addr;
        proxy_set_header X-Forwarded-For \\$proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto \\$scheme;

        proxy_http_version 1.1;
        proxy_set_header Upgrade \\$http_upgrade;
        proxy_set_header Connection \\"upgrade\\";
    }

    listen 443 ssl; # managed by Certbot
    ssl_certificate /etc/letsencrypt/live/xiaohongxia.ai1717.cn/fullchain.pem; # managed by Certbot
    ssl_certificate_key /etc/letsencrypt/live/xiaohongxia.ai1717.cn/privkey.pem; # managed by Certbot
    include /etc/letsencrypt/options-ssl-nginx.conf; # managed by Certbot
    ssl_dhparam /etc/letsencrypt/ssl-dhparams.pem; # managed by Certbot

}
server {
    if \(\\$host = xiaohongxia.ai1717.cn\) {
        return 301 https://\\$host\\$request_uri;
    } # managed by Certbot


    listen 80;
    server_name xiaohongxia.ai1717.cn;
    return 404; # managed by Certbot


}
EOF")

